// This code only looks at the CURRENT input to prevent hanging
const rawOutput = $json.output || "";

// Extract the JSON part from the AI's chatty response
const jsonMatch = rawOutput.match(/\{[\s\S]*\}/);

if (jsonMatch) {
  try {
    const parsedData = JSON.parse(jsonMatch[0]);

    // Return the parsed data directly
    // Because we updated the prompt, "Item Name" is already inside parsedData
    return parsedData;
  } catch (e) {
    return {
      "error": "Failed to parse JSON",
      "raw": rawOutput
    };
  }
} else {
  return {
    "error": "No JSON found",
    "raw": rawOutput
  };
}

