// 1. Get all rates from the previous HTTP node
const allRates = $input.first().json.rates;

// 2. Define the only currencies we want to keep
const aseanCodes = ["MYR", "SGD", "THB", "IDR", "PHP", "VND", "BND", "KHR", "LAK", "MMK"];

// 3. Create a clean, small object
const filteredRates = {};
aseanCodes.forEach(code => {
  if (allRates[code]) {
    filteredRates[code] = allRates[code];
  }
});

// 4. Return the tiny object
return {
  rates: filteredRates
};

const item = $("Loop Items").first().json;
const rates = $("Filter Currencies").first().json.rates;
const marginMultiplier = 1.40; // Cost + 25% Duty/Shipping + 15% Margin

const floorPrices = {};

// Safely calculate for all 10 countries
for (const [currency, rate] of Object.entries(rates)) {
  const floorValue = item["Item Cost (MYR)"] * rate * marginMultiplier;
  // Round to 2 decimal places for clean data
  floorPrices[currency] = parseFloat(floorValue.toFixed(2)); 
}

return {
  ...item,
  "Floor Prices": floorPrices
};

