// 1. Get data and run regex once
const routeText = $("Route Command").first().json.output;
const readSetItemJson = $("Read Set Item").first().json;
const setItemName = $("Set Item").first().json["Item Name"];
const match = routeText.match(/^\/setprice\s+(.+),\s*(.+),\s*(\d+(?:\.\d+)?)$/);

const category = match ? match[2] : null;
const price = match ? match[3] : null;

// 2. Logic checks
let row = readSetItemJson.row_number;
let keyExist = (category && category in readSetItemJson);

let message = "";

// 3. Determine specific error message
if (!row) {
  message = `Item ${setItemName} is not found.`;
} else if (!keyExist) {
  message = `Item ${setItemName} has no type ${category}`;
} else {
  message = `Item ${setItemName}, ${category} is set to ${price}!`;
}

return { text: message };

// Correctly reference the node data in n8n
const readSheetItems = $("Read Set Item").all(); 
const setItems = $("Set Item").all();

// Create a map for quick lookup by Item Name
const updateMap = new Map();
setItems.forEach(item => {
  // Access the .json property of the item
  updateMap.set(item.json["Item Name"], item.json);
});

// Map over the sheet data and merge updates
const updatedOutput = readSheetItems.map(item => {
  const row = item.json;
  const updateData = updateMap.get(row["Item Name"]);

  if (updateData) {
    // Return the updated object wrapped in the required { json: ... } format
    return {
      json: {
        ...row,
        ...updateData
      }
    };
  }
  // Return the original item if no update is found
  return item;
});

return updatedOutput;

// Get all items from the previous node
const items = Array.isArray($input.all()) ? $input.all() : [];

return items.map(item => {
  // Extract the JSON data from the n8n item structure
  const data = item.json;
  const newObj = {};

  Object.keys(data).forEach(key => {
    // Check if key should be kept
    if (!key.startsWith('Pending') && key !== 'row_number') {
      newObj[key] = data[key];
    }
  });

  return { json: newObj };
});
